import{_ as a,o,c as t,a0 as r}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Modelo Canônico de Memória Operacional","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_MEMORY_MODEL.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_MEMORY_MODEL.md","lastUpdated":1782593311000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_MEMORY_MODEL.md"};function i(n,e,d,c,m,l){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="modelo-canonico-de-memoria-operacional" tabindex="-1">Modelo Canônico de Memória Operacional <a class="header-anchor" href="#modelo-canonico-de-memoria-operacional" aria-label="Permalink to &quot;Modelo Canônico de Memória Operacional&quot;">​</a></h1><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>NEXUS é memória externa operacional para agentes e LLMs. Diferente de cache ou armazenamento frio, ela sustenta continuidade cognitiva: o agente retoma linhas de raciocínio, recupera decisões passadas e navega entre código, documentação e contexto abstrato sem depender exclusivamente da janela de contexto nativa.</p><p>A metáfora central é a de um <strong>organismo vivo</strong>: a memória não é um depósito flat de chunks, mas um sistema com camadas de rigidez distintas — esqueleto, carne e cartilagem — que se coordenam para viabilizar navegação precisa e adaptativa.</p><h2 id="o-triangulo-t3-→-t4-→-l3" tabindex="-1">O Triângulo T3 → T4 → L3 <a class="header-anchor" href="#o-triangulo-t3-→-t4-→-l3" aria-label="Permalink to &quot;O Triângulo T3 → T4 → L3&quot;">​</a></h2><p>A recuperação no NEXUS não é single-stage. Três mecanismos cooperam em sequência, cada um com um papel distinto:</p><table tabindex="0"><thead><tr><th>Camada</th><th>Substrato</th><th>Função</th><th>Metáfora</th></tr></thead><tbody><tr><td><strong>T3</strong></td><td>Qdrant (vetorial)</td><td>Detecção por proximidade vetorial — encontra sementes semanticamente próximas</td><td><strong>GPS</strong>: mostra onde você está no espaço semântico</td></tr><tr><td><strong>T4</strong></td><td>Grafo multi-relacional</td><td>Expansão topológica — caminha por dependências, similaridades e hierarquias entre arquivos</td><td><strong>Mapa de ruas</strong>: mostra rotas entre bairros do código</td></tr><tr><td><strong>L3</strong></td><td>Síntese emergente</td><td>Síntese de domínio que emerge de comunidades no T4, não de blob individual indexado</td><td><strong>Bairro</strong>: clusters de nós que juntos formam um conceito coerente</td></tr></tbody></table><h3 id="papel-de-cada-vertice" tabindex="-1">Papel de cada vértice <a class="header-anchor" href="#papel-de-cada-vertice" aria-label="Permalink to &quot;Papel de cada vértice&quot;">​</a></h3><p><strong>T3 (GPS)</strong> é a porta de entrada. O agente chega com uma pergunta em linguagem natural; T3 a embeda e localiza os pontos mais próximos no espaço vetorial. É rápido, impreciso por construção e serve para encontrar <em>onde começar</em>, não para entregar a resposta final.</p><p><strong>T4 (Mapa de ruas)</strong> é o expansor de contexto. A partir das sementes do T3, o T4 caminha pelo grafo multi-relacional: sobe via <code>part_of</code> para o arquivo, cruza via <code>depends_on:imports</code> ou <code>semantic_bridge</code> para arquivos relacionados, desce para chunks vizinhos. Cada aresta é uma projeção diferente do sistema — estrutural, semântica ou hierárquica.</p><p><strong>L3 (Bairro)</strong> não é um level fixo nem um blob pré-indexado. Diferente de L0/L1/L2 (níveis de chunk atômicos), L3 emerge on-the-fly por detecção de comunidades no T4. Um agente não &quot;consulta L3&quot; — ele navega pelo T4 até que um cluster semanticamente coerente se revele. A síntese de domínio é resultado da topologia, não de um documento pré-fabricado. L3 substitui o antigo conceito de &quot;abstração panorâmica&quot; por um mecanismo emergente.</p><h3 id="exemplo-concreto-do-triangulo" tabindex="-1">Exemplo concreto do triângulo <a class="header-anchor" href="#exemplo-concreto-do-triangulo" aria-label="Permalink to &quot;Exemplo concreto do triângulo&quot;">​</a></h3><p>Um agente perguntando &quot;como o sistema valida permissões de acesso?&quot; dispara o triângulo completo:</p><ol><li><strong>T3</strong> embeda a pergunta e encontra chunks sobre <code>AuthGuard</code>, <code>RBAC</code> e <code>PermissionService</code> — sementes próximas no espaço vetorial.</li><li><strong>T4</strong> recebe os node_ids desses chunks, sobe para os file nodes correspondentes, cruza por <code>depends_on:imports</code> para descobrir que <code>AuthGuard</code> usa <code>TokenService</code> e <code>UserRepository</code>, e desce para os chunks de implementação destes últimos.</li><li><strong>L3</strong> emerge da comunidade formada por esses nós — não como um documento separado, mas como o cluster topológico {AuthGuard, TokenService, UserRepository, PermissionService} que o agente reconhece como &quot;sistema de autorização&quot;.</li></ol><p>Sem T3, o agente não teria ponto de partida. Sem T4, ele teria só chunks isolados sem conexão. Sem L3, ele não saberia que aqueles arquivos formam um domínio coerente.</p><h3 id="por-que-tres-camadas-e-nao-duas" tabindex="-1">Por que três camadas e não duas <a class="header-anchor" href="#por-que-tres-camadas-e-nao-duas" aria-label="Permalink to &quot;Por que três camadas e não duas&quot;">​</a></h3><p>T3 e T4 resolvem problemas ortogonais. Proximidade vetorial (T3) não captura hierarquia estrutural — dois arquivos podem ser semanticamente próximos mas não ter relação de dependência. Topologia (T4) não captura similaridade difusa — dois arquivos podem depender do mesmo módulo sem serem semanticamente parecidos. L3 emerge justamente da interseção: comunidades densas no T4 que também são próximas no espaço T3. O triângulo não é redundância; é coordenação de mecanismos complementares.</p><h2 id="anatomia-da-memoria" tabindex="-1">Anatomia da Memória <a class="header-anchor" href="#anatomia-da-memoria" aria-label="Permalink to &quot;Anatomia da Memória&quot;">​</a></h2><p>O grafo T4 — e por extensão toda a memória operacional — tem três camadas de rigidez, como um organismo:</p><h3 id="tabela-de-camadas" tabindex="-1">Tabela de Camadas <a class="header-anchor" href="#tabela-de-camadas" aria-label="Permalink to &quot;Tabela de Camadas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Camada</th><th>Metáfora</th><th>Arestas</th><th>Mutabilidade</th><th>Função</th></tr></thead><tbody><tr><td><strong>Rígida</strong></td><td>Esqueleto</td><td><code>depends_on:imports</code>, <code>part_of</code></td><td>Fato — imutável</td><td>Relações estruturais que independem de modelo: A importa B no código-fonte, chunk pertence a um arquivo</td></tr><tr><td><strong>Semântica</strong></td><td>Carne</td><td><code>semantic_bridge</code>, <code>contradicts</code></td><td>Aproximação — mutável</td><td>Similaridades e conflitos detectados por embedding; mudam com threshold, modelo ou pipeline</td></tr><tr><td><strong>Classificação</strong></td><td>Cartilagem</td><td><code>file_type</code>, <code>project</code></td><td>Metadado — classifica os nós</td><td>Tags que permitem fatiar o grafo por formato, projeto ou tipo sem alterar a conectividade</td></tr></tbody></table><h3 id="por-que-a-anatomia-importa-para-a-memoria-operacional" tabindex="-1">Por que a anatomia importa para a memória operacional <a class="header-anchor" href="#por-que-a-anatomia-importa-para-a-memoria-operacional" aria-label="Permalink to &quot;Por que a anatomia importa para a memória operacional&quot;">​</a></h3><p>O agente não navega todo o grafo a cada consulta — isso seria computacionalmente inviável e cognitivamente disperso. A anatomia define <strong>prioridade de navegação</strong>:</p><ol><li><p><strong>Esqueleto primeiro.</strong> Arestas estruturais (<code>depends_on:imports</code>, <code>part_of</code>) são verdadeiras independente de modelo de embedding. O agente confia cegamente nelas para subir à árvore de arquivos, descer a chunks e cruzar dependências reais de importação. Essa é a âncora que impede deriva semântica.</p></li><li><p><strong>Carne depois.</strong> Arestas semânticas (<code>semantic_bridge</code>, <code>contradicts</code>) são dicas exploratórias. O agente usa para descobrir território desconhecido — arquivos que &quot;parecem com&quot; o atual — mas sabe que podem conter falsos positivos. Carne é hipótese, não fato.</p></li><li><p><strong>Cartilagem sempre.</strong> <code>file_type</code> e <code>project</code> filtram o escopo da navegação. O agente fatia o grafo por esses eixos para ignorar formatos irrelevantes (ex.: excluir JSON e YAML ao buscar regras de negócio) e focar no projeto correto.</p></li></ol><p>Essa priorização impede que o agente se perca em similaridades superficiais antes de estabelecer a âncora estrutural. É o que diferencia navegação guiada por topologia de busca puramente vetorial.</p><h3 id="como-a-anatomia-se-manifesta-no-runtime" tabindex="-1">Como a anatomia se manifesta no runtime <a class="header-anchor" href="#como-a-anatomia-se-manifesta-no-runtime" aria-label="Permalink to &quot;Como a anatomia se manifesta no runtime&quot;">​</a></h3><p>No fluxo de recuperação concreto, as três camadas aparecem em momentos diferentes:</p><ul><li><p><strong>Antes da consulta</strong> (indexação): o pipeline de enriquecimento classifica cada nó com <code>file_type</code> e <code>project</code> (cartilagem), extrai <code>depends_on:imports</code> do código-fonte (esqueleto), e calcula <code>semantic_bridge</code> e <code>contradicts</code> entre pares de arquivos (carne). As camadas são pré-computadas, não inferidas em tempo de query.</p></li><li><p><strong>Durante a expansão T4</strong>: o agente decide quais arestas seguir com base na confiança que cada camada merece. Para navegação estrutural (entender a arquitetura), segue só <code>depends_on:imports</code> — ignora a carne. Para descoberta exploratória (encontrar arquivos similares a um dado módulo), ativa <code>semantic_bridge</code> — mas trata os resultados como hipóteses.</p></li><li><p><strong>Na montagem do context pack</strong>: a cartilagem (<code>file_type</code>) ajuda o agente a priorizar formatos. Uma query sobre regras de negócio em TypeScript pode pular arquivos JSON, YAML ou markdown, mesmo que eles apareçam na expansão. O agente fatia o grafo pelos eixos de projeção no momento da hidratação.</p></li></ul><p>Essa separação entre o que é fato estrutural, o que é aproximação semântica e o que é classificação contingente permite que o agente navegue com granularidade variável — precisa quando precisa, difusa quando está explorando.</p><h2 id="capacidades-desejadas" tabindex="-1">Capacidades Desejadas <a class="header-anchor" href="#capacidades-desejadas" aria-label="Permalink to &quot;Capacidades Desejadas&quot;">​</a></h2><ol><li><strong>Recuperar casos antigos relevantes</strong> — o agente reencontra decisões, código e discussões anteriores mesmo depois de múltiplas sessões, sem depender de memória de trabalho do LLM.</li><li><strong>Relacionar código + decisão + contexto</strong> — uma única consulta conecta implementação (L1), intenção semântica (L2) e fundamentação arquitetural (reflections T5), formando um pacote coerente.</li><li><strong>Sustentar continuidade além da janela nativa</strong> — a memória externa faz o papel que o contexto LLM não consegue: reter longas linhas de raciocínio entre interações, cruzando sessões e pausas.</li><li><strong>Transferência entre contextos</strong> — solução encontrada em um módulo é navegável para outro módulo análogo via expansão T4, sem necessidade de reconsulta ou re-embedagem.</li></ol><h2 id="o-que-nao-e-o-objetivo" tabindex="-1">O Que Não É o Objetivo <a class="header-anchor" href="#o-que-nao-e-o-objetivo" aria-label="Permalink to &quot;O Que Não É o Objetivo&quot;">​</a></h2><ul><li><strong>Não é ontologia rígida.</strong> O NEXUS não impõe o que &quot;merece&quot; virar conhecimento. A ingestão permanece ampla — código, notas, markdowns, decisões e rascunhos entram sem curadoria prévia. Camadas derivadas servem para navegação, não para policiar o corpus.</li><li><strong>Não é busca flat.</strong> O sucesso não depende exclusivamente de <code>top_k</code> no Qdrant. A expansão T4 e a síntese emergente L3 são o que diferenciam o sistema de um retriever vetorial commodity.</li><li><strong>Não é verdade absoluta.</strong> As camadas semânticas (carne) são aproximações. O agente precisa calibrar o nível de confiança conforme a camada — esqueleto é fato, carne é hipótese.</li></ul><h2 id="runtime-atual" tabindex="-1">Runtime Atual <a class="header-anchor" href="#runtime-atual" aria-label="Permalink to &quot;Runtime Atual&quot;">​</a></h2><p>O fluxo de recuperação ativo segue três estágios:</p><ol><li><strong>Entrada T3.</strong> A consulta é embedada e busca sementes por similaridade vetorial no Qdrant.</li><li><strong>Expansão T4.</strong> A partir das sementes, o grafo multi-relacional expande o contexto: sobe via <code>part_of</code> para o nó arquivo, cruza via <code>depends_on</code> ou <code>semantic_bridge</code> para arquivos relacionados, desce para chunks vizinhos.</li><li><strong>Hidratação T2.</strong> O Postgres fornece conteúdo bruto, metadados, caminho e versão para montar os context packs entregues ao agente.</li></ol><p>O resultado é um <strong>context pack</strong>: uma janela coerente de memória que combina código-fonte (L0), estrutura AST (L1), sumário semântico (L2) e relacionamentos topológicos (T4) — não uma lista flat de chunks.</p><h2 id="leituras-complementares" tabindex="-1">Leituras Complementares <a class="header-anchor" href="#leituras-complementares" aria-label="Permalink to &quot;Leituras Complementares&quot;">​</a></h2><ul><li><code>../NEXUS Docs/CANONICAL_ARCHITECTURE.md</code> — síntese das camadas T1–T6 e invariantes arquiteturais do sistema</li><li><code>../NEXUS Docs/CANONICAL_RUNTIME.md</code> — contrato operacional atual: endpoints, formato de resposta e fluxo de query</li><li><code>../NEXUS Docs/CANONICAL_T4.md</code> — reconciliação conceitual do T4: visão original, compromisso operacional e direção de evolução</li><li><code>T4_GRAPH_NORMS.md</code> — normas estruturais do grafo T4: tipos de nó, arestas, eixos de projeção, padrões de navegação e métricas atuais</li></ul>',39)])])}const g=a(s,[["render",i]]);export{p as __pageData,g as default};
